using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests;

internal static class TestHelper
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(dbName)
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Seeds a standard set of test data into the context.
    /// </summary>
    public static void SeedTestData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var department = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        context.Departments.Add(department);
        context.SaveChanges();

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = department.DepartmentID
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = department.DepartmentID
        };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        var student1 = new Student
        {
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };
        var student2 = new Student
        {
            FirstMidName = "Meredith",
            LastName = "Alonso",
            EnrollmentDate = DateTime.Parse("2019-09-01")
        };
        var student3 = new Student
        {
            FirstMidName = "Arturo",
            LastName = "Anand",
            EnrollmentDate = DateTime.Parse("2021-06-01")
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        context.Enrollments.Add(new Enrollment
        {
            StudentID = student1.ID,
            CourseID = course1.CourseID,
            Grade = Grade.A
        });
        context.SaveChanges();
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_ValidInputs_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 → 4 pages")]
    [DataRow(20, 10, 2, DisplayName = "20 items, page size 10 → 2 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 → 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 → 0 pages")]
    [DataRow(21, 7, 3, DisplayName = "21 items, page size 7 → 3 pages")]
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedPages)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsAllItemsToList()
    {
        // Arrange
        var items = new List<int> { 10, 20, 30 };

        // Act
        var list = new PaginatedList<int>(items, 30, 1, 10);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(10, list[0]);
        Assert.AreEqual(20, list[1]);
        Assert.AreEqual(30, list[2]);
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "First page has no previous")]
    [DataRow(2, true, DisplayName = "Second page has previous")]
    [DataRow(5, true, DisplayName = "Fifth page has previous")]
    public void HasPreviousPage_VariousPageIndices_ReturnsExpected(int pageIndex, bool expected)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

        // Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 30, 10, true, DisplayName = "First of 3 pages has next")]
    [DataRow(3, 30, 10, false, DisplayName = "Last page has no next")]
    [DataRow(2, 30, 10, true, DisplayName = "Middle page has next")]
    [DataRow(1, 5, 10, false, DisplayName = "Single page has no next")]
    public void HasNextPage_VariousScenarios_ReturnsExpected(int pageIndex, int count, int pageSize, bool expected)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectSlice()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
