        Assert.AreEqual(3, chemistry.Credits);
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollmentsWithGrades()
    {
        // Arrange
        using var context = TestHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify at least one enrollment has a grade
        var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).ToList();
        Assert.IsTrue(enrollmentsWithGrades.Count > 0, "Expected at least one enrollment with a grade");

        // Verify one enrollment without a grade (Anand in Chemistry)
        var noGradeEnrollments = context.Enrollments.Where(e => e.Grade == null).ToList();
        Assert.IsTrue(noGradeEnrollments.Count > 0, "Expected at least one enrollment without a grade");
    }

    [TestMethod]
    public void Initialize_CalledTwice_DoesNotDuplicate()
    {
        // Arrange
        using var context = TestHelper.CreateContext();

        // Act
        DbInitializer.Initialize(context);
        DbInitializer.Initialize(context);

        // Assert - counts should remain the same
        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(7, context.Courses.Count());
        Assert.AreEqual(11, context.Enrollments.Count());
    }
