+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class NotificationServiceTests
+{
+    private NotificationService _sut;
+
+    [TestInitialize]
+    public void Setup()
+    {
+        _sut = new NotificationService();
+        // Drain the static queue from any previous tests
+        while (_sut.ReceiveNotification() != null) { }
+    }
+
+    [TestCleanup]
+    public void Cleanup()
+    {
+        _sut?.Dispose();
+    }
+
+    [TestMethod]
+    public void SendNotification_ValidInput_EnqueuesNotification()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("Student", notification.EntityType);
+        Assert.AreEqual("1", notification.EntityId);
+        Assert.AreEqual("CREATE", notification.Operation);
+        Assert.AreEqual("Admin", notification.CreatedBy);
+        Assert.IsFalse(notification.IsRead);
+    }
+
+    [TestMethod]
+    public void SendNotification_WithoutUserName_DefaultsToSystem()
+    {
+        // Act
+        _sut.SendNotification("Course", "101", EntityOperation.UPDATE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("System", notification.CreatedBy);
+    }
+
+    [TestMethod]
+    public void SendNotification_NullUserName_DefaultsToSystem()
+    {
+        // Act
+        _sut.SendNotification("Course", "101", "Math", EntityOperation.UPDATE, null);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("System", notification.CreatedBy);
+    }
+
+    [TestMethod]
+    public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("Course 'Math' has been updated", notification.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
+    {
+        // Act
+        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _sut.SendNotification("Student", "42", EntityOperation.CREATE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_UpdateWithoutDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _sut.SendNotification("Instructor", "7", EntityOperation.UPDATE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
+    }
+
+    [TestMethod]
+    public void SendNotification_DeleteWithoutDisplayName_UsesIdInMessage()
+    {
+        // Act
+        _sut.SendNotification("Course", "101", EntityOperation.DELETE);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.AreEqual("Course (ID: 101) has been deleted", notification.Message);
+    }
+
+    [TestMethod]
+    public void ReceiveNotification_EmptyQueue_ReturnsNull()
+    {
+        // Act
+        var result = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.IsNull(result);
+    }
+
+    [TestMethod]
+    public void ReceiveNotification_MultipleNotifications_ReturnsFIFOOrder()
+    {
+        // Arrange
+        _sut.SendNotification("A", "1", EntityOperation.CREATE);
+        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
+        _sut.SendNotification("C", "3", EntityOperation.DELETE);
+
+        // Act & Assert
+        Assert.AreEqual("A", _sut.ReceiveNotification().EntityType);
+        Assert.AreEqual("B", _sut.ReceiveNotification().EntityType);
+        Assert.AreEqual("C", _sut.ReceiveNotification().EntityType);
+        Assert.IsNull(_sut.ReceiveNotification());
+    }
+
+    [TestMethod]
+    public void MarkAsRead_AnyId_DoesNotThrow()
+    {
+        // MarkAsRead is a no-op in this in-memory implementation
+        _sut.MarkAsRead(1);
+        _sut.MarkAsRead(0);
+        _sut.MarkAsRead(999);
+        // No exception expected
+    }
+
+    [TestMethod]
+    public void SendNotification_SetsCreatedAtTimestamp()
+    {
+        // Arrange
+        var before = System.DateTime.Now.AddSeconds(-1);
+
+        // Act
+        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
+        var after = System.DateTime.Now.AddSeconds(1);
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.IsNotNull(notification);
+        Assert.IsTrue(notification.CreatedAt >= before, "CreatedAt should be >= before timestamp");
+        Assert.IsTrue(notification.CreatedAt <= after, "CreatedAt should be <= after timestamp");
+    }
+
+    [TestMethod]
+    public void Dispose_CanBeCalledMultipleTimes()
+    {
+        // Act & Assert - should not throw
+        _sut.Dispose();
+        _sut.Dispose();
+    }
+
+    [TestMethod]
+    public void SendNotification_TwoArgOverload_DelegatesToFiveArgOverload()
+    {
+        // Act - use the 4-arg overload (entityType, entityId, operation, userName)
+        _sut.SendNotification("Instructor", "5", EntityOperation.UPDATE, "Admin");
+        var notification = _sut.ReceiveNotification();
+
+        // Assert
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("Instructor", notification.EntityType);
+        Assert.AreEqual("5", notification.EntityId);
+        Assert.AreEqual("UPDATE", notification.Operation);
+        Assert.AreEqual("Admin", notification.CreatedBy);
+        // Without display name, message uses ID format
+        Assert.AreEqual("Instructor (ID: 5) has been updated", notification.Message);
+    }
+}
+

